            html.forEach(it => {
                d.push({
                    title: it.title,
                    img: 'https://img1.vbwus.com' + it.path,
                    desc: (it.mask || (it.playlist && it.playlist.title) || '') + ' ⭐' + it.score,
                    url: it.id
                });
            });
